import React, { useState } from "react";
import { Link } from "react-router-dom";
import { FaSearch, FaBars, FaTimes } from "react-icons/fa";
import logo from "../assets/logo.png"; // Make sure your logo is in src/assets/

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const links = [
    { name: "Home", path: "/" },
    { name: "About", path: "/about" },
    { name: "Purpose", path: "/purpose" },
    { name: "Vision", path: "/vision" },
    { name: "Domains", path: "/domains" },
    { name: "Team", path: "/team" },
    { name: "Careers", path: "/careers" },
    { name: "Contact", path: "/contact" },
  ];

  return (
    <nav className="fixed top-0 left-0 w-full bg-white shadow-md z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">

          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2">
            <img src={logo} alt="Godemar's Empire Logo" className="h-10 w-10 object-contain"/>
            <span className="text-2xl font-bold text-gray-900">Godemar’s Empire</span>
          </Link>

          {/* Desktop Links */}
          <div className="hidden md:flex space-x-6 items-center">
            {links.map((link, index) => (
              <Link
                key={index}
                to={link.path}
                className="text-gray-700 hover:text-blue-600"
              >
                {link.name}
              </Link>
            ))}

            {/* Search Icon */}
            <button className="p-2 rounded-full hover:bg-gray-200">
              <FaSearch className="text-gray-700"/>
            </button>
          </div>

          {/* Mobile Hamburger */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 rounded-md hover:bg-gray-200"
            >
              {isOpen ? <FaTimes size={24}/> : <FaBars size={24}/>}
            </button>
          </div>

        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white shadow-lg">
          <div className="flex flex-col px-4 py-4 space-y-2">
            {links.map((link, index) => (
              <Link
                key={index}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="text-gray-700 hover:text-blue-600"
              >
                {link.name}
              </Link>
            ))}

            {/* Search Icon for Mobile */}
            <button className="flex items-center space-x-2 p-2 rounded-md hover:bg-gray-200">
              <FaSearch className="text-gray-700"/>
              <span>Search</span>
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
